class Solution:
    def canMakeSubsequence(self, str1: str, str2: str) -> bool:
        m, n = len(str1), len(str2)
        i, j = 0, 0
        while i < m and j < n:
            if str1[i] == str2[j]:
                j += 1
            i += 1
        if j == n:
            return True
        i, j = m - 1, n - 1
        while i >= 0 and j >= 0:
            if str1[i] == str2[j]:
                j -= 1
            i -= 1
        return j < 0

